#include<iostream>
using namespace std;
int m,n;
const int N=10010;
int a[N],f[N][N];
int main(){
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	for(int i=0;i<=n;i++)f[i][0]=1;
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			if(j<a[i])f[i][j]=f[i-1][j];	
			else f[i][j]=f[i-1][j]+f[i-1][j-a[i]];
		}
	}
	cout<<f[n][m];
}
